-- ============================================================
-- TRNC Health — Duty List (Nöbetçi Eczane) June 2026
-- Run this in Supabase SQL Editor
-- ============================================================

CREATE TABLE IF NOT EXISTS duty_list (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  duty_date date NOT NULL,
  open_from text NOT NULL DEFAULT '08:00',
  open_until text NOT NULL DEFAULT '00:00',
  name text NOT NULL,
  address text,
  phone text,
  region text
);

ALTER TABLE duty_list ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Anyone can read duty_list" ON duty_list;
CREATE POLICY "Anyone can read duty_list" ON duty_list
  FOR SELECT TO authenticated USING (true);

CREATE INDEX IF NOT EXISTS duty_list_date_idx ON duty_list (duty_date);

-- Clear existing June data before re-inserting
DELETE FROM duty_list WHERE duty_date BETWEEN '2026-06-01' AND '2026-06-30';

